sourcesContent:
let getTinhTong = (req, res) => {
    try {
        let id = req.params.id;

        return res.status(200).json({
            errCode: 0,
            message: "Lấy id thành công!",
            data: {
                id: id
            }
        });
    } catch (e) {
        console.log(e);
        return res.status(500).json({
            errCode: -1,
            message: "Lỗi từ server..."
        });
    }
}

let postTinhTongHaiSo = (req, res) => {
    try {
        let { soA, soB } = req.body;

        if (soA === undefined || soB === undefined) {
            return res.status(400).json({
                errCode: 1,
                message: "Thiếu dữ liệu đầu vào (soA hoặc soB)!"
            });
        }

        // Chuyển sang dạng số để tính toán
        let numA = parseFloat(soA);
        let numB = parseFloat(soB);
        let tong = numA + numB;

        return res.status(200).json({
            errCode: 0,
            message: "Tính tổng 2 số thành công!",
            data: {
                soA: numA,
                soB: numB,
                tong: tong
            }
        });
    } catch (e) {
        console.log(e);
        return res.status(500).json({
            errCode: -1,
            message: "Lỗi từ server..."
        });
    }
}

module.exports = {
    getTinhTong: getTinhTong,
    postTinhTongHaiSo: postTinhTongHaiSo
}

